class Solution {
public:
    int removePalindromeSub(string s) {
        if (s.empty()) {
            return 0;
        }
        int left = 0;
        int right = s.length() - 1;
        while (left < right && s[left] == s[right]) {
            left++;
            right--;
        }
        return (left < right) ? 2 : 1;
    }
};
```
